int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals;
    vals.reserve(n);
    for (int i = 0; i < n; ++i) {
        int x;
        if (!(cin >> x)) break;
        vals.push_back(x);
    }
    ListNode* head = nullptr;
    ListNode* tail = nullptr;
    for (int v : vals) {
        ListNode* node = new ListNode(v);
        if (!head) head = tail = node;
        else { tail->next = node; tail = node; }
    }
    Solution sol;
    ListNode* newHead = sol.deleteHead(head);
    vector<int> out;
    for (ListNode* cur = newHead; cur; cur = cur->next) out.push_back(cur->val);
    cout << out.size() << "\n";
    if (!out.empty()) {
        for (size_t i = 0; i < out.size(); ++i) {
            if (i) cout << ' ';
            cout << out[i];
        }
        cout << "\n";
    }
    return 0;
